import{c as n,S as i,j as h,m as a}from"./chunks/framework.8aa1YH_s.js";const u=JSON.parse('{"title":"Bộ đề thi","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/bo-de-thi.md","filePath":"hoc-vien/bo-de-thi.md","lastUpdated":0}'),o={name:"hoc-vien/bo-de-thi.md"};function l(r,t,e,c,g,s){return i(),h("div",null,[...t[0]||(t[0]=[a('<h1 id="bo-đe-thi" tabindex="-1">Bộ đề thi <a class="header-anchor" href="#bo-đe-thi" aria-label="Permalink to “Bộ đề thi”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/luyen-tap/bo-de-thi/:id</code></p><p>Bộ đề thi là <strong>một tập hợp nhiều đề thi cùng chủ đề</strong> mà bạn có thể luyện đều đặn để <strong>đạt cường độ thi thử cao</strong>.</p><h2 id="khi-nao-nen-dung-bo-đe" tabindex="-1">Khi nào nên dùng bộ đề? <a class="header-anchor" href="#khi-nao-nen-dung-bo-đe" aria-label="Permalink to “Khi nào nên dùng bộ đề?”">​</a></h2><ul><li>Bạn đã học xong khóa lý thuyết, cần <strong>chạy nước rút</strong>.</li><li>Trước kỳ thi 1-3 tháng - cần làm đề liên tục.</li><li>Muốn <strong>thi thử theo lịch</strong>: vd 1 đề/tuần liên tục 12 tuần.</li><li>Cần <strong>so sánh tiến bộ</strong> qua nhiều lần làm đề.</li></ul><h2 id="cac-loai-bo-đe-tren-he-thong" tabindex="-1">Các loại bộ đề trên hệ thống <a class="header-anchor" href="#cac-loai-bo-đe-tren-he-thong" aria-label="Permalink to “Các loại bộ đề trên hệ thống”">​</a></h2><table tabindex="0"><thead><tr><th>Bộ đề</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Bộ đề HSA 2026</strong></td><td>20-30 đề mẫu chất lượng cho ĐGNL</td></tr><tr><td><strong>Bộ đề TSA 2026</strong></td><td>15-25 đề mẫu cho ĐGTD</td></tr><tr><td><strong>Bộ đề TNTHPT Toán 2026</strong></td><td>30 đề mẫu môn Toán</td></tr><tr><td><strong>Bộ đề TNTHPT KHTN/KHXH</strong></td><td>Đề theo tổ hợp</td></tr><tr><td><strong>Bộ đề chuyên đề Toán 12</strong></td><td>Đề luyện từng chuyên đề (Hàm số, Lượng giác, ...)</td></tr><tr><td><strong>Bộ đề trường chuyên</strong></td><td>Đề khó từ các trường chuyên</td></tr></tbody></table><h2 id="tim-bo-đe-o-đau" tabindex="-1">Tìm bộ đề ở đâu? <a class="header-anchor" href="#tim-bo-đe-o-đau" aria-label="Permalink to “Tìm bộ đề ở đâu?”">​</a></h2><h3 id="tren-trang-chu" tabindex="-1">Trên trang chủ <a class="header-anchor" href="#tren-trang-chu" aria-label="Permalink to “Trên trang chủ”">​</a></h3><ul><li>Khu vực <strong>&quot;Bộ đề thi nổi bật&quot;</strong>.</li></ul><h3 id="menu-đieu-huong" tabindex="-1">Menu điều hướng <a class="header-anchor" href="#menu-đieu-huong" aria-label="Permalink to “Menu điều hướng”">​</a></h3><ul><li>Bấm <strong>Bộ đề thi</strong> → chọn loại kỳ thi.</li></ul><h3 id="trong-khoa-cua-ban" tabindex="-1">Trong khóa của bạn <a class="header-anchor" href="#trong-khoa-cua-ban" aria-label="Permalink to “Trong khóa của bạn”">​</a></h3><ul><li>Nhiều khóa có <strong>bộ đề kèm theo</strong> ở cuối chương trình.</li></ul><h2 id="trang-chi-tiet-bo-đe" tabindex="-1">Trang chi tiết bộ đề <a class="header-anchor" href="#trang-chi-tiet-bo-đe" aria-label="Permalink to “Trang chi tiết bộ đề”">​</a></h2><p><code>https://lamsonedutech.vn/luyen-tap/bo-de-thi/:id</code> hiển thị:</p><ul><li><strong>Tên bộ đề</strong> + giáo viên biên soạn</li><li><strong>Số đề thành phần</strong>: vd &quot;30 đề - 30 tuần&quot;</li><li><strong>Tiến độ</strong>: bạn đã làm bao nhiêu đề</li><li><strong>Lịch gợi ý</strong> (nếu giáo viên đặt): &quot;Đề 1 - Tuần 1&quot;, &quot;Đề 2 - Tuần 2&quot;...</li><li><strong>Danh sách từng đề</strong> kèm trạng thái: <ul><li>🔒 Chưa mở khóa (chỉ mở khi tới ngày)</li><li>🆕 Mới (chưa làm)</li><li>✅ Đã làm (có điểm)</li><li>🔁 Có thể làm lại</li></ul></li></ul><h2 id="mua-bo-đe" tabindex="-1">Mua bộ đề <a class="header-anchor" href="#mua-bo-đe" aria-label="Permalink to “Mua bộ đề”">​</a></h2><ul><li>Có bộ <strong>miễn phí</strong> đi kèm khóa học bạn đã mua.</li><li>Có bộ <strong>bán riêng</strong> - cần mua như mua khóa thường (xem <a href="./mua-khoa-hoc">Mua khóa học</a>).</li><li>Một số bộ chỉ mua được <strong>theo gói trọn năm</strong>.</li></ul><h2 id="lam-đe-trong-bo" tabindex="-1">Làm đề trong bộ <a class="header-anchor" href="#lam-đe-trong-bo" aria-label="Permalink to “Làm đề trong bộ”">​</a></h2><ol><li>Bấm vào đề cụ thể trong bộ.</li><li>Trang xem trước hiển thị: số câu, thời gian, điểm cao nhất bạn từng đạt.</li><li>Bấm <strong>Bắt đầu</strong>.</li><li>Làm bài như đề thi thông thường.</li></ol><h2 id="theo-doi-tien-bo-qua-bo-đe" tabindex="-1">Theo dõi tiến bộ qua bộ đề <a class="header-anchor" href="#theo-doi-tien-bo-qua-bo-đe" aria-label="Permalink to “Theo dõi tiến bộ qua bộ đề”">​</a></h2><p>Trang <strong>Tiến độ</strong> của bộ đề:</p><h3 id="bieu-đo-điem-qua-cac-lan" tabindex="-1">Biểu đồ điểm qua các lần <a class="header-anchor" href="#bieu-đo-điem-qua-cac-lan" aria-label="Permalink to “Biểu đồ điểm qua các lần”">​</a></h3><ul><li>Trục X: đề số 1, 2, 3, ...</li><li>Trục Y: điểm bạn đạt.</li><li>Đường tiến bộ - bạn có đang tăng?</li></ul><h3 id="bang-tong-hop" tabindex="-1">Bảng tổng hợp <a class="header-anchor" href="#bang-tong-hop" aria-label="Permalink to “Bảng tổng hợp”">​</a></h3><table tabindex="0"><thead><tr><th>Đề</th><th>Lần làm</th><th>Điểm</th><th>Thời gian</th><th>Xếp hạng</th></tr></thead><tbody><tr><td>Đề 1</td><td>12/01/2026</td><td>720</td><td>192 phút</td><td>234/1500</td></tr><tr><td>Đề 2</td><td>19/01/2026</td><td>780</td><td>188 phút</td><td>156/1500</td></tr><tr><td>...</td><td></td><td></td><td></td><td></td></tr></tbody></table><h3 id="phan-tich-chu-đe-yeu" tabindex="-1">Phân tích chủ đề yếu <a class="header-anchor" href="#phan-tich-chu-đe-yeu" aria-label="Permalink to “Phân tích chủ đề yếu”">​</a></h3><ul><li>Tổng hợp các câu sai nhiều xuyên suốt bộ đề.</li><li>Gợi ý chuyên đề cần ôn lại.</li></ul><h2 id="bang-xep-hang-bo-đe" tabindex="-1">Bảng xếp hạng bộ đề <a class="header-anchor" href="#bang-xep-hang-bo-đe" aria-label="Permalink to “Bảng xếp hạng bộ đề”">​</a></h2><ul><li>Khi nhiều người làm cùng bộ, có <strong>bảng xếp hạng tổng</strong> (cộng dồn điểm các đề).</li><li>So sánh với cộng đồng học viên cùng mục tiêu.</li></ul><h2 id="chien-luoc-dung-bo-đe" tabindex="-1">Chiến lược dùng bộ đề <a class="header-anchor" href="#chien-luoc-dung-bo-đe" aria-label="Permalink to “Chiến lược dùng bộ đề”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Làm theo lịch cố định</p><ul><li>Mỗi tuần 1 đề, <strong>cố định thời gian</strong> (vd thứ Bảy 14:00-17:00).</li><li>Tạo thói quen như thi thật.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Đừng làm 2 đề liên tiếp</p><ul><li>Sẽ mỏi mệt, kết quả không phản ánh thật.</li><li>Sau 1 đề, dành 1-2 ngày <strong>phân tích lỗi</strong> rồi mới làm đề tiếp.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">So sánh đề đầu - đề cuối</p><ul><li>Đầu bộ: làm để <strong>đo baseline</strong>.</li><li>Cuối bộ: làm lại đề đầu → so điểm để đo tiến bộ.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Lưu lại bài sai để ôn</p><ul><li>Tạo file Word/Notion ghi lại <strong>các câu hay sai</strong> + lý do.</li><li>Trước kỳ thi 1 tuần, xem lại file này (không cần làm lại đề).</li></ul></div><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi muốn nhảy cóc làm đề 15 mà chưa làm đề 1-14?</strong> → Tùy bộ đề. Một số bộ <strong>mở khóa tự do</strong>, có bộ yêu cầu làm theo thứ tự.</p><p><strong>Đề trong bộ có khó dần lên không?</strong> → Thường bộ đề được sắp xếp <strong>độ khó tăng dần</strong> hoặc <strong>chia theo chủ đề</strong>. Đọc mô tả bộ đề để biết.</p><p><strong>Tôi mua bộ đề HSA, có dùng được bộ TSA không?</strong> → Không - mỗi bộ tính riêng. Cần mua riêng từng bộ.</p><p><strong>Sau khi hoàn thành toàn bộ bộ đề, hệ thống có cấp chứng nhận?</strong> → Một số bộ có cấp <strong>chứng nhận hoàn thành</strong> (PDF). Tải về tại trang chi tiết bộ đề khi hoàn tất.</p>',41)])])}const b=n(o,[["render",l]]);export{u as __pageData,b as default};
